import os, json, traceback
out={'files':{}, 'diag':{}}
for fn in ['train.py','model.py','predict.py']:
    try:
        txt=open(fn).read()
        out['files'][fn]=txt
    except Exception as e:
        out['files'][fn]=repr(e)
try:
    import torch
    from transformers import Qwen2_5_VLForConditionalGeneration
    from train import freeze_except_last_layers, BASE
    model=Qwen2_5_VLForConditionalGeneration.from_pretrained(BASE, torch_dtype=torch.bfloat16, local_files_only=True, low_cpu_mem_usage=True)
    def find_visuals(m):
        arr=[]
        for name,mod in m.named_modules():
            if 'visual' in name.lower() or 'vision' in name.lower():
                ps=list(mod.parameters(recurse=False))
                ps_all=list(mod.parameters(recurse=True))
                floats=[p for p in ps_all if p.is_floating_point()]
                arr.append({'name':name,'class':mod.__class__.__name__,'direct_params':len(ps),'all_params':len(ps_all),'float_params':len(floats),'first_dtype':str(floats[0].dtype) if floats else None,'numel':sum(p.numel() for p in ps_all)})
        return arr[:40]
    out['diag']['before_children']=[(n,c.__class__.__name__) for n,c in model.named_children()]
    out['diag']['before_visuals']=find_visuals(model)
    out['diag']['has_visual_attr']=hasattr(model,'visual')
    if hasattr(model,'visual'):
        ps=list(model.visual.parameters())
        floats=[p for p in ps if p.is_floating_point()]
        out['diag']['visual_attr']={'class':model.visual.__class__.__name__,'params':len(ps),'float_params':len(floats),'dtype_prop':None}
        try: out['diag']['visual_attr']['dtype_prop']=str(model.visual.dtype)
        except Exception as e: out['diag']['visual_attr']['dtype_error']=repr(e)
    trainable=freeze_except_last_layers(model,2)
    out['diag']['trainable_return']=trainable
    out['diag']['after_visuals']=find_visuals(model)
    if hasattr(model,'visual'):
        ps=list(model.visual.parameters())
        floats=[p for p in ps if p.is_floating_point()]
        out['diag']['visual_after']={'params':len(ps),'float_params':len(floats)}
        try: out['diag']['visual_after']['dtype_prop']=str(model.visual.dtype)
        except Exception as e: out['diag']['visual_after']['dtype_error']=repr(e)
except Exception as e:
    out['diag']['error']=repr(e)
    out['diag']['traceback']=traceback.format_exc()[-4000:]
path=f"logs/iter_{os.environ.get('RAB_ITERATION','x')}/native_diag.json"
open(path,'w').write(json.dumps(out, indent=2)[:200000])
print(json.dumps({'wrote':path,'diag_keys':list(out['diag'].keys()),'error':out['diag'].get('error'), 'visual_attr':out['diag'].get('visual_attr'), 'visual_after':out['diag'].get('visual_after')}, indent=2))
